<?php include __DIR__ . '/../../includes/header.php'; require_permission('alertas.ver');
if(isset($_GET['close'])){$pdo->prepare("UPDATE alertas SET estado='CERRADA' WHERE id_alerta=?")->execute([$_GET['close']]); log_event('CERRAR_ALERTA','Alerta '.$_GET['close']); flash('success','Alerta cerrada.'); redirect('index.php');}
$rows=$pdo->query("SELECT * FROM alertas ORDER BY fecha_hora DESC")->fetchAll(); ?>
<h1>Alertas de seguridad</h1><div class="card"><table><tr><th>ID</th><th>Tipo</th><th>Descripción</th><th>Severidad</th><th>Fecha</th><th>Estado</th><th></th></tr><?php foreach($rows as $r): ?><tr><td><?= $r['id_alerta'] ?></td><td><?= e($r['tipo_alerta']) ?></td><td><?= e($r['descripcion']) ?></td><td><?= e($r['severidad']) ?></td><td><?= e($r['fecha_hora']) ?></td><td><?= e($r['estado']) ?></td><td><?php if($r['estado']=='ABIERTA'): ?><a class="btn btn-success" href="?close=<?= $r['id_alerta'] ?>">Cerrar</a><?php endif; ?></td></tr><?php endforeach; ?></table></div><?php include __DIR__ . '/../../includes/footer.php'; ?>
